import{_ as e,o as r,c as t,a2 as s}from"./chunks/framework.BS3ZfcoS.js";const m=JSON.parse('{"title":"心理咨询师谈中年危机","description":"","frontmatter":{"title":"心理咨询师谈中年危机","author":"","collection":"职场成长","series_order":17,"total_chars":782},"headers":[],"relativePath":"career/midlife-crisis.md","filePath":"career/midlife-crisis.md"}'),o={name:"career/midlife-crisis.md"};function p(i,a,n,l,c,d){return r(),t("div",null,[...a[0]||(a[0]=[s('<h2 id="s-608" tabindex="-1">心理咨询师谈中年危机系列 <a class="header-anchor" href="#s-608" aria-label="Permalink to &quot;心理咨询师谈中年危机系列 {#s-608}&quot;">​</a></h2><p>共3个视频</p><h3 id="s-609" tabindex="-1">心理咨询师谈中年危机（一）——为什么不鼓励脆弱 <a class="header-anchor" href="#s-609" aria-label="Permalink to &quot;心理咨询师谈中年危机（一）——为什么不鼓励脆弱 {#s-609}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **社会不鼓励脆弱，只鼓励阳性——效率、KPI、金钱、成功、自律，仿佛只有这些才值得宣扬</p><h4 id="s-610" tabindex="-1">2. 很多大学生不敢表露抑郁情绪，怕被屏蔽；意志力能解决的问题其实非常有限 <a class="header-anchor" href="#s-610" aria-label="Permalink to &quot;2. 很多大学生不敢表露抑郁情绪，怕被屏蔽；意志力能解决的问题其实非常有限 {#s-610}&quot;">​</a></h4><p>**3. **中国有心理问题患者7000多万，潜在1.9亿；取证150万人但专职稳定输出的不到1万，供需严重失衡</p><p><strong>金句</strong></p><p><em>「意志力能解决的问题其实是非常有限的」</em></p><p><strong>行动指南</strong></p><p>正视脆弱，不要只用意志力硬扛心理问题</p><h3 id="s-611" tabindex="-1">心理咨询师谈中年危机（二）——落井下石式教育与年龄危机 <a class="header-anchor" href="#s-611" aria-label="Permalink to &quot;心理咨询师谈中年危机（二）——落井下石式教育与年龄危机 {#s-611}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **落井下石式教育——孩子掉井里不拉还骂你不听话，导致孩子觉得自己是废物无价值</p><p>**2. **心理咨询两个高峰期：14-25岁（学业/家庭/进入社会）和29-35岁（30岁焦虑/生育压力/35岁危机）</p><h4 id="s-612" tabindex="-1">3. 人生转折点如蛇蜕皮般脆弱，更需要社会支持；&quot;出名要趁早&quot;是社会PUA <a class="header-anchor" href="#s-612" aria-label="Permalink to &quot;3. 人生转折点如蛇蜕皮般脆弱，更需要社会支持；&quot;出名要趁早&quot;是社会PUA {#s-612}&quot;">​</a></h4><p><strong>金句</strong></p><p><em>「很多家长的教育都是落井下石，你已经掉井里了，不是拉你上来而是骂你不听话」</em></p><p><strong>行动指南</strong></p><p>识别落井下石式教育的模式，在人生转折点主动寻求社会支持而非独自承受</p><h3 id="s-613" tabindex="-1">心理咨询师谈中年危机（三）——青春期没解决的问题中年会回归 <a class="header-anchor" href="#s-613" aria-label="Permalink to &quot;心理咨询师谈中年危机（三）——青春期没解决的问题中年会回归 {#s-613}&quot;">​</a></h3><p><strong>核心观点</strong></p><p>**1. **中年危机的人在青春期就已被淹没——青春期是认识自己整合自己的机会，压力太大被虐成渣就错过了</p><p>**2. **没完成成长任务就匆忙进入下一阶段，速度更快再无机会重整，到中年压力加大时崩溃</p><p>**3. **青春期没解决的问题不会消失，只是蛰伏着到中年以另一种形式回归，直到正面解决</p><p><strong>金句</strong></p><p><em>「在青春期的时候没能被解决的问题，它们并不会消失，只是蛰伏着，到了你中年的时候以另一种形式回归，直到你把他给正面解决掉」</em></p><p><strong>行动指南</strong></p><p>趁青春期完成自我认识和整合，不逃避问题正面解决</p>',29)])])}const _=e(o,[["render",p]]);export{m as __pageData,_ as default};
